module sr_latch(  
    input S,  
    input R,  
    output reg obf_Q  
);  
    always @ (S or R) begin  
        if (S && R)  
            ; // Invalid state, do nothing  
        else if (S)  
            obf_Q = 1; // Set  
        else if (R)  
            obf_Q = 0; // Reset  
    end  
endmodule
